const payload = $json.body ?? $json;
const clean = (value) => value === undefined || value === null ? '' : String(value).trim();
const companyName = clean(payload.company_name || payload.company || payload.Company || payload['Company Name']);
const contactEmail = clean(payload.contact_email || payload.email || payload.Email || payload['Work Email']).toLowerCase();
if (!companyName) throw new Error('Clay row rejected: company_name is required');
if (!contactEmail || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(contactEmail)) throw new Error('Clay row rejected: a valid contact_email is required');
const firstName = clean(payload.first_name || payload['First Name']);
const lastName = clean(payload.last_name || payload['Last Name']);
const contactName = clean(payload.contact_name || payload.name || payload['Full Name']) || [firstName, lastName].filter(Boolean).join(' ');
const row = {
  company_name: companyName,
  website: clean(payload.website || payload.domain || payload['Company Domain']),
  location: clean(payload.location || payload.city || payload['Company Location']),
  org_type: clean(payload.org_type || payload.industry || payload.Industry),
  cmmc_level_sought: clean(payload.cmmc_level_sought),
  employee_count: clean(payload.employee_count || payload['Employee Count']),
  contact_name: contactName,
  contact_title: clean(payload.contact_title || payload.title || payload['Job Title']),
  contact_email: contactEmail,
  contact_linkedin: clean(payload.contact_linkedin || payload.linkedin_url || payload['LinkedIn URL'])
};
return [{ json: { mapping: Object.fromEntries(Object.keys(row).map((key) => [key, key])), all_rows: [row], category: clean(payload.category) || 'sales', business_line: clean(payload.business_line) || 'cmmc', persona_slug: payload.persona_slug || null } }];
